-- DROP DATABASE IF EXISTS retail_tshirts;
-- CREATE DATABASE retail_tshirts;
-- USE retail_tshirts;

CREATE TABLE t_shirts(
t_shirt_id INT AUTO_INCREMENT PRIMARY KEY,
brand VARCHAR(50),
color VARCHAR(30),
size VARCHAR(5),
material VARCHAR(30),
fit VARCHAR(20),
gender VARCHAR(10),
sleeve_type VARCHAR(20),
rating DECIMAL(2,1),
supplier VARCHAR(30),
launch_year INT,
price INT,
stock_quantity INT);

CREATE TABLE discounts(
discount_id INT AUTO_INCREMENT PRIMARY KEY,
t_shirt_id INT,
pct_discount DECIMAL(5,2),
FOREIGN KEY(t_shirt_id) REFERENCES t_shirts(t_shirt_id));

